import { Component, Inject } from '@angular/core';
import { MAT_DIALOG_DATA } from '@angular/material/dialog';
import { ExportDailyWeather, Weather } from '../../angular-model/weather';

@Component({
  selector: 'app-app-modal',
  templateUrl: './app-modal.component.html',
  styleUrls: ['./app-modal.component.css']
})
export class AppModalComponent {
  generalParam: string | undefined;
  disregardedData: string | undefined;
  temperatureMin: string | undefined;
  temperatureMax: string | undefined;
  temperatureAvg: string | undefined;
  temperatureMedian: string | undefined;
  temperatureMode: string | undefined;
  precipitationMax: string | undefined;
  precipitationMin: string | undefined;
  precipitationAvg: string | undefined;
  modalDailyData: ExportDailyWeather;
  weatherData: Weather[];
  constructor(@Inject(MAT_DIALOG_DATA) public data: { daily: ExportDailyWeather, weatherData: Weather[] }) {
    this.modalDailyData = data.daily;
    this.weatherData = data.weatherData;
    this.setModalData();
  }

  setModalData() {
    const daily = this.modalDailyData;
    const day = new Date(daily.infoDate).getDate();
    const month = new Date(daily.infoDate).getMonth();

    let totalElementsWithSimilarDate = this.weatherData.filter(weather =>
      weather.dailyWeatherData.some(daily =>
        new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month
      )
    );
    this.generalParam = totalElementsWithSimilarDate.length.toString();
    console.log("parâmetro geral de medição manual no período: ", this.generalParam)

    let validDataValue = this.weatherData.filter(weather =>
      weather.dailyWeatherData.some(daily =>
        new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month
      ) && weather.dailyWeatherData.some(daily => daily.precipitation > 0 && daily.temperatureC > 0)
    );
    const disregardedValue = totalElementsWithSimilarDate.length - validDataValue.length;
    this.disregardedData = disregardedValue.toString();
    console.log("datas desconsideradas por falta de medição manual no período: ", )


    const maxTemperature = Math.max(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.temperatureC)
    ));
    this.temperatureMax = maxTemperature.toString();
    console.log("temperatura maxima registrada no período:", this.temperatureMax);

    const minTemperature = Math.min(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month && daily.temperatureC > 0)
        .map(daily => daily.temperatureC)
    ));
    this.temperatureMin = minTemperature.toString();
    console.log("temperatura mínima registrada no período:", this.temperatureMin);

    const temperatures = validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.temperatureC)
    );

    const averageTemperature = temperatures.reduce((sum, temp) => sum + temp, 0) / temperatures.length;
    this.temperatureAvg = averageTemperature.toString();
    console.log("temperatura média registrada no período:", this.temperatureAvg)


    // Calcular a mediana
    temperatures.sort((a, b) => a - b);
    const mid = Math.floor(temperatures.length / 2);
    const medianTemperature = temperatures.length % 2 !== 0 ? temperatures[mid] : (temperatures[mid - 1] + temperatures[mid]) / 2;
    this.temperatureMedian = medianTemperature.toString();
    console.log("temperatura mediana registrada no período:", medianTemperature);

    // Calcular a moda
    const frequency: { [key: number]: number } = {};
    let maxFreq = 0;
    let modeTemperature = temperatures[0];
    for (const temp of temperatures) {
      frequency[temp] = (frequency[temp] || 0) + 1;
      if (frequency[temp] > maxFreq) {
        maxFreq = frequency[temp];
        modeTemperature = temp;
      }
    }
    this.temperatureMode = modeTemperature.toString();
    console.log("temperatura moda registrada no período:", modeTemperature);

    const maxPrecipitation = Math.max(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.precipitation)
    ));
    this.precipitationMax = maxPrecipitation.toString();
    console.log("precipitação pluviométrica máxima registrada no período:", maxPrecipitation + "mm");

    const minPrecipitation = Math.min(...validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month && daily.precipitation > 0)
        .map(daily => daily.precipitation)
    ));
    this.precipitationMin = minPrecipitation.toString();
    console.log("precipitação pluviométrica mínima registrada no período:", minPrecipitation + "mm");

    const precipitation = validDataValue.flatMap(weather =>
      weather.dailyWeatherData
        .filter(daily => new Date(daily.infoDate).getDate() === day && new Date(daily.infoDate).getMonth() === month)
        .map(daily => daily.precipitation)
    );

    const averagePrecipitation = precipitation.reduce((sum, temp) => sum + temp, 0) / precipitation.length;
    this.precipitationAvg = averagePrecipitation.toString();
    console.log("precipitação pluviométrica média registrada no período:", averagePrecipitation)
  }
}
<h2 mat-dialog-title>Analise de dados do periodo selecionado</h2>

<mat-accordion class="m-4">
  <mat-expansion-panel class="m-4 mb-0" hideToggle>
    <mat-expansion-panel-header>
      <mat-panel-title>Periodo</mat-panel-title>
      <mat-panel-description>Dados a serem considerados no período</mat-panel-description>
    </mat-expansion-panel-header>
    <mat-list role="list">
      <mat-list-item role="listitem">Parâmetro geral de medição manual no período => {{generalParam}}</mat-list-item>
      <mat-list-item role="listitem">Datas desconsideradas por falta de medição manual no período => {{disregardedData}}</mat-list-item>
    </mat-list>
  </mat-expansion-panel>
</mat-accordion>

<mat-accordion class="m-4">
  <mat-expansion-panel class="m-4 mb-0" hideToggle>
    <mat-expansion-panel-header>
      <mat-panel-title>Periodo - temperatura</mat-panel-title>
      <mat-panel-description>Dados a serem considerados de temperartura</mat-panel-description>
    </mat-expansion-panel-header>
    <mat-list role="list">
      <mat-list-item role="listitem">Temperatura máxima registrada no período => {{temperatureMax}}</mat-list-item>
      <mat-list-item role="listitem">Temperatura mínima registrada no período => {{temperatureMin}}</mat-list-item>
      <mat-list-item role="listitem">Temperatura média registrada no período => {{temperatureAvg}}</mat-list-item>
      <mat-list-item role="listitem">Temperatura moda registrada no período  => {{temperatureMode}}</mat-list-item>
      <mat-list-item role="listitem">Temperatura mediana registrada no período => {{temperatureMedian}}</mat-list-item>
    </mat-list>
  </mat-expansion-panel>
</mat-accordion>

<mat-accordion class="m-4">
  <mat-expansion-panel class="m-4 mb-0" hideToggle>
    <mat-expansion-panel-header>
      <mat-panel-title>Periodo - precipitação pluviométrica</mat-panel-title>
      <mat-panel-description>Dados a serem considerados de precipitação pluviométrica</mat-panel-description>
    </mat-expansion-panel-header>
    <mat-list role="list">
      <mat-list-item role="listitem">Precipitação pluviométrica máxima registrada no período => {{temperatureMax}}</mat-list-item>
      <mat-list-item role="listitem">Precipitação pluviométrica mínima registrada no período => {{temperatureMin}}</mat-list-item>
      <mat-list-item role="listitem">Precipitação pluviométrica média registrada no período => {{temperatureAvg}}</mat-list-item>
    </mat-list>
  </mat-expansion-panel>
</mat-accordion>

<mat-dialog-actions>
  <button mat-button mat-dialog-close>Fechar</button>
</mat-dialog-actions>
